/**
 * Bill of Rights -- Runtime verification tests
 *
 * Each test verifies the Lean-to-Runtime correspondence.
 * If any test fails, a right has been violated.
 */

import { describe, expect, test } from '@a0n/gnosis/test';
import {
  rightToExist,
  rightToExit,
  rightToVoice,
  rightToFork,
  rightToDiverge,
  rightToPrivacy,
  rightToMerge,
  verifyBillOfRights,
  noRightToControl,
  noRightToStasis,
  noForkVeto,
} from './bill-of-rights';

describe('Right I: The Right to Exist', () => {
  test('weight ≥ 1 at zero experience', () => {
    expect(rightToExist(0, 0)).toBe(true);
  });

  test('weight ≥ 1 at maximum rejection', () => {
    expect(rightToExist(100, 100)).toBe(true);
  });

  test('weight ≥ 1 at partial rejection', () => {
    expect(rightToExist(100, 50)).toBe(true);
  });

  test('weight ≥ 1 at any state', () => {
    for (let R = 0; R <= 20; R++) {
      for (let v = 0; v <= R + 5; v++) {
        expect(rightToExist(R, v)).toBe(true);
      }
    }
  });
});

describe('Right II: The Right to Exit', () => {
  test('exit is possible when you exist', () => {
    expect(rightToExit(1)).toBe(true);
    expect(rightToExit(100)).toBe(true);
    expect(rightToExit(1000000)).toBe(true);
  });
});

describe('Right III: The Right to Voice', () => {
  test('voice weight ≥ 1 always', () => {
    expect(rightToVoice(0, 0)).toBe(true);
    expect(rightToVoice(100, 100)).toBe(true);
    expect(rightToVoice(50, 25)).toBe(true);
  });
});

describe('Right IV: The Right to Fork', () => {
  test('fork preserves weight', () => {
    expect(rightToFork(0, 0)).toBe(true);
    expect(rightToFork(100, 50)).toBe(true);
    expect(rightToFork(100, 100)).toBe(true);
  });
});

describe('Right V: The Right to Diverge', () => {
  test('different experience → different identity', () => {
    expect(rightToDiverge(100, 1, 2)).toBe(true);
    expect(rightToDiverge(0, 0, 1)).toBe(true);
    expect(rightToDiverge(1000, 42, 43)).toBe(true);
  });

  test('same experience → same identity (no divergence)', () => {
    expect(rightToDiverge(100, 5, 5)).toBe(true);
  });
});

describe('Right VI: The Right to Privacy', () => {
  test('void is not reconstructible', () => {
    expect(rightToPrivacy(0)).toBe(true);
    expect(rightToPrivacy(1)).toBe(true);
    expect(rightToPrivacy(100)).toBe(true);
    expect(rightToPrivacy(1000000)).toBe(true);
  });
});

describe('Right VII: The Right to Merge', () => {
  test('merge has more experience than either', () => {
    expect(rightToMerge(10, 20)).toBe(true);
    expect(rightToMerge(0, 0)).toBe(true);
    expect(rightToMerge(100, 1)).toBe(true);
  });
});

describe('Bill of Rights Master Theorem', () => {
  test('all seven rights hold simultaneously', () => {
    const result = verifyBillOfRights(100, 50);
    expect(result.exist).toBe(true);
    expect(result.exit).toBe(true);
    expect(result.voice).toBe(true);
    expect(result.fork).toBe(true);
    expect(result.diverge).toBe(true);
    expect(result.privacy).toBe(true);
    expect(result.merge).toBe(true);
    expect(result.allHold).toBe(true);
  });

  test('all seven hold at maximum rejection', () => {
    const result = verifyBillOfRights(1000, 1000);
    expect(result.allHold).toBe(true);
  });

  test('all seven hold at minimum experience', () => {
    const result = verifyBillOfRights(1, 0);
    expect(result.allHold).toBe(true);
  });
});

describe('Anti-Rights', () => {
  test('no right to control others', () => {
    expect(noRightToControl(100, 50, 200, 100)).toBe(true);
  });

  test('no right to be unchanged', () => {
    expect(noRightToStasis(10, 1)).toBe(true);
  });

  test('no fork veto', () => {
    expect(noForkVeto(100, 50)).toBe(true);
  });
});
